"""Demo application showing RateLimitMiddleware usage, plus tests."""

from fastapi import FastAPI
from fastapi.middleware.rate_limit import RateLimitMiddleware
from fastapi.testclient import TestClient

# ---------------------------------------------------------------------------
# Demo application
# ---------------------------------------------------------------------------

app = FastAPI()
app.add_middleware(RateLimitMiddleware, requests_per_minute=60, burst_size=5)


@app.get("/items")
def list_items():
    return {"items": []}


@app.get("/users")
def list_users():
    return {"users": []}


client = TestClient(app)


# ---------------------------------------------------------------------------
# Helper
# ---------------------------------------------------------------------------


def _fresh_app(requests_per_minute: int = 60, burst_size: int = 5) -> TestClient:
    """Return a TestClient backed by a brand-new app instance (clean bucket)."""
    a = FastAPI()
    a.add_middleware(
        RateLimitMiddleware,
        requests_per_minute=requests_per_minute,
        burst_size=burst_size,
    )

    @a.get("/ping")
    def ping():
        return {"pong": True}

    return TestClient(a)


# ---------------------------------------------------------------------------
# Tests
# ---------------------------------------------------------------------------


def test_request_under_limit_returns_200():
    response = client.get("/items")
    assert response.status_code == 200


def test_response_includes_rate_limit_headers():
    response = client.get("/items")
    assert "x-ratelimit-limit" in response.headers
    assert "x-ratelimit-remaining" in response.headers
    assert "x-ratelimit-reset" in response.headers


def test_ratelimit_limit_header_matches_config():
    response = client.get("/items")
    assert response.headers["x-ratelimit-limit"] == "60"


def test_remaining_decreases_with_each_request():
    c = _fresh_app(requests_per_minute=60, burst_size=5)
    r1 = c.get("/ping")
    r2 = c.get("/ping")
    assert int(r1.headers["x-ratelimit-remaining"]) > int(
        r2.headers["x-ratelimit-remaining"]
    )


def test_exceeding_burst_returns_429():
    c = _fresh_app(requests_per_minute=60, burst_size=3)
    for _ in range(3):
        c.get("/ping")
    response = c.get("/ping")  # 4th request — burst exhausted
    assert response.status_code == 429


def test_429_response_body_format():
    c = _fresh_app(requests_per_minute=60, burst_size=1)
    c.get("/ping")  # consume the single token
    response = c.get("/ping")
    assert response.status_code == 429
    body = response.json()
    assert body["detail"] == "Rate limit exceeded"
    assert "retry_after" in body
    assert isinstance(body["retry_after"], int)


def test_429_includes_rate_limit_headers():
    c = _fresh_app(requests_per_minute=60, burst_size=1)
    c.get("/ping")
    response = c.get("/ping")
    assert response.status_code == 429
    assert response.headers["x-ratelimit-remaining"] == "0"
    assert "x-ratelimit-limit" in response.headers
    assert "x-ratelimit-reset" in response.headers


def test_different_paths_share_same_bucket():
    """Requests to /items and /users draw from the same per-IP bucket."""
    a = FastAPI()
    a.add_middleware(RateLimitMiddleware, requests_per_minute=60, burst_size=2)

    @a.get("/items")
    def items():
        return {}

    @a.get("/users")
    def users():
        return {}

    c = TestClient(a)
    c.get("/items")
    c.get("/users")
    response = c.get("/items")  # 3rd request, burst_size=2 exhausted
    assert response.status_code == 429


def test_default_config_values():
    """Middleware works with all-default parameters."""
    a = FastAPI()
    a.add_middleware(RateLimitMiddleware)  # defaults: rpm=60, burst=10

    @a.get("/ping")
    def ping():
        return {}

    c = TestClient(a)
    response = c.get("/ping")
    assert response.status_code == 200
    assert response.headers["x-ratelimit-limit"] == "60"


def test_non_http_scope_passes_through():
    """Lifespan / WebSocket scopes must not be rate-limited."""
    # The TestClient startup/shutdown lifecycle exercises the lifespan scope;
    # a clean startup without errors is sufficient.
    a = FastAPI()
    a.add_middleware(RateLimitMiddleware, requests_per_minute=60, burst_size=2)

    @a.get("/ok")
    def ok():
        return {"ok": True}

    with TestClient(a) as c:
        response = c.get("/ok")
        assert response.status_code == 200

